#include <stdio.h>

// Function prototypes (declarations)
int add(int, int);           // Returns int, takes two ints
float divide(float, float);  // Returns float, takes two floats
void greet(void);            // Returns nothing, takes no arguments
char toUpper(char);          // Returns char, takes one char

int main() {
    printf("Sum: %d\n", add(10, 20));
    printf("Division: %.2f\n", divide(15.0, 4.0));
    greet();
    printf("Uppercase: %c\n", toUpper('a'));
    return 0;
}

// Function definitions
int add(int a, int b) {
    return a + b;
}

float divide(float x, float y) {
    return x / y;
}

void greet(void) {
    printf("Hello!\n");
}

char toUpper(char c) {
    return c - 32;  // Simple ASCII conversion
}

#include <stdio.h>

// Forward declarations (prototypes)
int isEven(int n);   // Declared before isOdd
int isOdd(int n);

int main() {
    int num = 7;
    if (isEven(num))
        printf("%d is even\n", num);
    else
        printf("%d is odd\n", num);
    return 0;
}

// Function definitions
int isEven(int n) {
    if (n == 0)
        return 1;  // True - even
    else
        return isOdd(n - 1);  // Call isOdd
}

int isOdd(int n) {
    if (n == 0)
        return 0;  // False - not even
    else
        return isEven(n - 1);  // Call isEven
}

#include <stdio.h>

// Function prototypes with pointers
void swap(int *a, int *b);           // Pointers to integers
void modifyArray(int *arr, int n);   // Pointer to array
int* createNumber(int n);            // Returns pointer to integer

int main() {
    int x = 10, y = 20;
    printf("Before swap: x=%d, y=%d\n", x, y);
    swap(&x, &y);  // Pass addresses
    printf("After swap: x=%d, y=%d\n", x, y);

    int arr[5] = {1, 2, 3, 4, 5};
    modifyArray(arr, 5);
    printf("Array after modify: ");
    for (int i = 0; i < 5; i++)
        printf("%d ", arr[i]);
    printf("\n");

    int *ptr = createNumber(100);
    printf("Created number: %d\n", *ptr);
    return 0;
}

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

void modifyArray(int *arr, int n) {
    for (int i = 0; i < n; i++)
        arr[i] *= 2;  // Double each element
}

int* createNumber(int n) {
    static int value;
    value = n;
    return &value;
}
